package com.cognizant.springtesting; import static org.mockito.ArgumentMatchers.any; import static org.mockito.Mockito.verify; import static org.mockito.Mockito.when; import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post; import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*; import org.junit.jupiter.api.Test; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest; import org.springframework.boot.test.mock.mockito.MockBean; import org.springframework.http.MediaType; import org.springframework.test.web.servlet.MockMvc; import com.fasterxml.jackson.databind.ObjectMapper;
@WebMvcTest(UserController.class) public class UserControllerPostTest {@Autowired MockMvc mockMvc; @Autowired ObjectMapper objectMapper; @MockBean UserService userService; @Test void testCreateUser() throws Exception {User user=new User(1L,"Aman");when(userService.saveUser(any(User.class))).thenReturn(user);mockMvc.perform(post("/users").contentType(MediaType.APPLICATION_JSON).content(objectMapper.writeValueAsString(user))).andExpect(status().isOk()).andExpect(jsonPath("$.id").value(1)).andExpect(jsonPath("$.name").value("Aman"));verify(userService).saveUser(any(User.class));}}
